mapper.select:
select * from t_r_ai_document



        and doc_type = #{docType}


order by updated_at desc

select * from t_r_ai_document



        and doc_type = #{docType}


order by updated_at desc

select id, workspace_ids, doc_type, engine_type, source_ref, title, description, indexed_at, created_at, updated_at, created_by, updated_by from t_r_ai_document
and doc_type = #{docType}
order by updated_at desc

select * from t_r_ai_document
where source_ref = #{sourceRef}
limit 1

select *, match(title, content) against(#{q} in natural language mode) as score
from t_r_ai_document
where match(title, content) against(#{q} in natural language mode)


    and doc_type = #{docType}


    and (engine_type is null or engine_type in
        #{et}
    )

order by score desc
limit #{limit}
